var doc = Rhino.RhinoDoc.ActiveDoc;
var rows = new List<object>();
foreach (var idef in doc.InstanceDefinitions)
{
    if (idef == null) continue;
    var objs = idef.GetObjects();
    rows.Add(new { name = idef.Name, id = idef.Id.ToString(), member_count = objs?.Length ?? 0 });
}
return new { definition_count = rows.Count, definitions = rows };
